#include <stdio.h>
int maxAlternatingSum(int arr[], int n) {
    int incl = arr[0];
    int excl = 0;
    for (int i = 1; i < n; i++) {
        int new_excl = (incl > excl) ? incl : excl;
        incl = excl + arr[i];
        excl = new_excl;
    }
    return (incl > excl) ? incl : excl;
}
int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    printf("%d\n", maxAlternatingSum(arr, n));
    return 0;
}

